var html = src;
var m = html.match(/var encryptedData = "([^"]+)"/);
if (m) {
  var enc = m[1];
  var rawBytes = java.base64DecodeToByteArray(enc, 0);
  var rawStr = java.bytesToStr(rawBytes, "ISO-8859-1");
  var ivStr = rawStr.substring(0, 16);
  var ctStr = rawStr.substring(16);
  var ivBytes = java.strToBytes(ivStr, "ISO-8859-1");
  var ctBytes = java.strToBytes(ctStr, "ISO-8859-1");
  var key = 'tH1rU6qZ4vU1sK7pN1wO7mX4bY6dQ9gX'.substr(0, 32);
  var cipher = java.createSymmetricCrypto("aes/cbc/pkcs7padding", java.strToBytes(key), ivBytes);
  var decBytes = cipher.decrypt(ctBytes);
  var jsonStr = java.bytesToStr(decBytes, "UTF-8");
  var urls = JSON.parse(jsonStr);
  var imgs = [];
  for (var i = 0; i < urls.length; i++) {
    imgs.push('<img src="' + urls[i] + ',' + JSON.stringify({headers:{Referer:'https://guiwb.nnmh.info/'}}) + '">');
  }
  imgs.join('');
}

