    let data = JSON.parse(result).data;
    if (!data || !data.length) return "";
    // 反转图片顺序
    let reversedData = data.reverse();
    // 生成图片列表，并添加样式和referrerpolicy属性
    let imgsHtml = reversedData.map(function(item) {
        return '<img src="' + item.img + '" style="max-width:100%; display:block;" referrerpolicy="no-referrer">';
    }).join('');
    return imgsHtml;
})();

